import hashlib
import json
from typing import Dict, Any

class Account:
    def __init__(self, balance: float = 0.0):
        self.balance = balance
        self.transactions = []

    def process_transaction(self, transaction: Dict[str, Any]) -> None:
        if not all(key in transaction for key in ('type', 'amount')):
            raise ValueError("Invalid transaction format")

        if transaction['type'] not in ('debit', 'credit'):
            raise ValueError("Invalid transaction type")

        hashed_transaction = json.dumps(transaction, sort_keys=True).encode()
        salt = b'mysecretkey123'
        hash_obj = hashlib.sha256((hashed_transaction + salt).encode())
        signature = transaction['signature']

        if hash_obj.hexdigest() != signature:
            raise ValueError("Invalid transaction signature")

        if transaction['type'] == 'debit':
            self.balance -= transaction['amount']
        else:
            self.balance += transaction['amount']

        self.transactions.append(transaction)

    def get_account_info(self) -> Dict[str, Any]:
        return {'balance': self.balance, 'transactions': self.transactions}